import "testing"

func TestBullyElectionSkipsDeadHighestIDPeer(t *testing.T) {
	be := NewBullyElection("node-1")
	be.AddPeer("node-2")
	be.AddPeer("node-3")
	be.AddPeer("node-4")
	be.MarkDead("node-4")

	if got := be.RunElection(); got != "node-3" {
		t.Fatalf("RunElection() = %q, want highest live peer %q", got, "node-3")
	}
	if got := be.Leader(); got != "node-3" {
		t.Fatalf("Leader() = %q, want %q", got, "node-3")
	}
}

func TestBullyElectionReelectsNextLivePeerAfterLeaderDies(t *testing.T) {
	be := NewBullyElection("node-1")
	be.AddPeer("node-2")
	be.AddPeer("node-3")
	be.AddPeer("node-4")

	if got := be.RunElection(); got != "node-4" {
		t.Fatalf("initial RunElection() = %q, want %q", got, "node-4")
	}

	be.MarkDead("node-4")

	if got := be.RunElection(); got != "node-3" {
		t.Fatalf("RunElection() after leader death = %q, want %q", got, "node-3")
	}
	if be.IsLeader() {
		t.Fatal("local node reported leader after a higher live peer was elected")
	}
}

func TestBullyElectionAllAliveBehaviorUnchanged(t *testing.T) {
	tests := []struct {
		name  string
		self  string
		peers []string
		want  string
	}{
		{
			name:  "highest registered peer wins",
			self:  "node-1",
			peers: []string{"node-2", "node-3", "node-4"},
			want:  "node-4",
		},
		{
			name:  "local node wins when it has the highest ID",
			self:  "node-4",
			peers: []string{"node-1", "node-2", "node-3"},
			want:  "node-4",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			be := NewBullyElection(tt.self)
			for _, id := range tt.peers {
				be.AddPeer(id)
			}

			if got := be.RunElection(); got != tt.want {
				t.Fatalf("RunElection() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestBullyElectionNoLivePeersHasNoLeader(t *testing.T) {
	be := NewBullyElection("node-1")
	be.AddPeer("node-1")
	be.AddPeer("node-2")
	be.MarkDead("node-1")
	be.MarkDead("node-2")

	if got := be.RunElection(); got != "" {
		t.Fatalf("RunElection() = %q, want no leader", got)
	}
	if got := be.Leader(); got != "" {
		t.Fatalf("Leader() = %q, want no leader", got)
	}
	if be.IsLeader() {
		t.Fatal("IsLeader() = true, want false with no live peers")
	}
	if got := be.CurrentState(); got != StateFollower {
		t.Fatalf("CurrentState() = %s, want %s", got, StateFollower)
	}
}
